package dev.harrison.rendacomcarro.finance;import dev.harrison.rendacomcarro.finance.application.*;import dev.harrison.rendacomcarro.finance.domain.*;import dev.harrison.rendacomcarro.support.PostgresIntegrationTest;import java.math.BigDecimal;import java.time.LocalDate;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.test.context.TestPropertySource;import static org.assertj.core.api.Assertions.assertThat;
@SpringBootTest@TestPropertySource(properties={"APP_ADMIN_USERNAME=finance-owner","APP_ADMIN_PASSWORD=finance-owner-credential"})class FinancialObligationFlowTest extends PostgresIntegrationTest {@Autowired FinancialObligationService service;@Test void flexiblePaymentReducesPrincipalWithoutBecomingOperatingExpense(){var o=service.create(new FinancialObligationService.CreateCommand(null,ObligationType.FAMILY_LOAN,ObligationMode.FLEXIBLE,"Família",new BigDecimal("30000"),BigDecimal.ZERO,LocalDate.now(),null,null,null,new BigDecimal("500"),null));service.pay(o.getId(),LocalDate.now(),new BigDecimal("500"),BigDecimal.ZERO,BigDecimal.ZERO,"PAY-1",null);assertThat(service.get(o.getId()).getCurrentBalance()).isEqualByComparingTo("29500.00");}}
